const data = $input.first().json;

let message = `*تقرير تحليل المخزون اليومي (نظام وكيل)* 📊\n\n`;
const summary = data.scan_summary || {};
message += `📦 إجمالي المنتجات التي تم فحصها: ${summary.total_products_checked || 0}\n`;
message += `📉 منتجات منخفضة المخزون: ${summary.low_stock_count || 0}\n`;
message += `⚠️ تنبؤ بنقص المخزون (استباقي): ${summary.predicted_shortage_count || 0}\n`;
message += `🐢 منتجات بطيئة الحركة: ${summary.slow_moving_count || 0}\n`;
message += `⏳ منتجات تقترب من انتهاء الصلاحية: ${summary.near_expiry_count || 0}\n\n`;

if (data.alerts && data.alerts.length > 0) {
  message += `*🚨 التنبيهات التفصيلية:*\n`;
  data.alerts.forEach((alert, index) => {
    let typeAr = alert.alert_type;
    if (typeAr === 'predicted_shortage') typeAr = 'نقص متوقع';
    else if (typeAr === 'low_stock') typeAr = 'مخزون منخفض';
    else if (typeAr === 'slow_moving') typeAr = 'بطيء الحركة';
    else if (typeAr === 'near_expiry') typeAr = 'قريب الانتهاء';

    let details = '';
    if (alert.alert_type === 'predicted_shortage' && alert.metadata && alert.metadata.days_until_stockout) {
        details = ` (ينتهي خلال ${Math.round(alert.metadata.days_until_stockout)} يوم)`;
    }

    message += `${index + 1}. [${typeAr}] منتج رقم: ${alert.product_id}${details}\n`;
  });
}

if (data.rfq_drafts && data.rfq_drafts.length > 0) {
    message += `\n*📝 مسودات طلبات عروض الأسعار (RFQ):* تم إنشاء ${data.rfq_drafts.length} مسودة.\n`;
}
if (data.pricing_recs && data.pricing_recs.length > 0) {
    message += `\n*💰 توصيات التسعير:* تم اقتراح ${data.pricing_recs.length} تعديل للأسعار.\n`;
}

return { json: { message: message, original_data: data } };
